"""Servicio CRUD endpoints — generated by scripts/new_entity.py."""

from __future__ import annotations

import csv
import hashlib
from io import StringIO

from fastapi import APIRouter, Depends, File, UploadFile
from fastapi.responses import Response
from sqlalchemy.ext.asyncio import AsyncSession

from app.api.deps import get_current_user, get_db, require_permission
from app.api.deps_ownership import require_ownership
from app.core.catalog_csv import read_csv_dict_rows, servicio_row, servicio_template_body
from app.core.permissions import P
from app.core.response import success
from app.models.servicio import Servicio
from app.models.user import User
from app.schemas.servicio import ServicioCreate, ServicioRead, ServicioUpdate
from app.services.audit_service import record as audit_record
from app.services.celula_service import celula_svc
from app.services.servicio_service import servicio_svc

router = APIRouter()


@router.get("/export.csv")
async def export_servicios_csv(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(require_permission(P.CATALOGS.VIEW)),
):
    items = await servicio_svc.list(db, filters={"user_id": current_user.id})
    buf = StringIO()
    writer = csv.writer(buf)
    writer.writerow(["id", "nombre", "descripcion", "criticidad", "tecnologia_stack", "celula_id"])
    for r in items:
        writer.writerow(
            [
                str(r.id),
                r.nombre,
                r.descripcion or "",
                r.criticidad,
                r.tecnologia_stack or "",
                str(r.celula_id),
            ]
        )
    body = buf.getvalue()
    digest = hashlib.sha256(body.encode("utf-8")).hexdigest()
    await audit_record(
        db,
        action="servicio.export_csv",
        entity_type="servicio",
        entity_id=current_user.id,
        metadata={"rows": len(items), "sha256": digest, "format": "csv"},
    )
    return Response(
        content=body,
        media_type="text/csv; charset=utf-8",
        headers={"Content-Disposition": 'attachment; filename="servicios.csv"'},
    )


@router.get("/import-template.csv")
async def download_servicio_import_template(
    _db: AsyncSession = Depends(get_db),
    current_user: User = Depends(require_permission(P.CATALOGS.CREATE)),
):
    body = servicio_template_body()
    return Response(
        content=body,
        media_type="text/csv; charset=utf-8",
        headers={"Content-Disposition": 'attachment; filename="servicios_import_template.csv"'},
    )


@router.post("/import")
async def import_servicios_csv(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(require_permission(P.CATALOGS.CREATE)),
    file: UploadFile = File(..., description="CSV con cabecera (ver import-template)"),
):
    raw = await file.read()
    digest = hashlib.sha256(raw).hexdigest()
    text = raw.decode("utf-8-sig")
    rows = read_csv_dict_rows(text)
    err_list: list[dict] = []
    created = 0

    for line_no, d in enumerate(rows, start=2):
        parsed, perr = servicio_row(d, row=line_no)
        if perr is not None:
            err_list.append({"row": line_no, "message": perr})
            continue
        assert parsed is not None
        cel = await celula_svc.get(db, parsed.celula_id, scope={"user_id": current_user.id})
        if not cel:
            err_list.append({"row": line_no, "message": "celula_id inexistente o sin acceso"})
            continue
        await servicio_svc.create(db, parsed, extra={"user_id": current_user.id})
        created += 1

    await audit_record(
        db,
        action="servicio.import_csv",
        entity_type="servicio",
        entity_id=current_user.id,
        metadata={
            "rows_in_file": len(rows),
            "created": created,
            "row_errors": len(err_list),
            "sha256": digest,
            "format": "csv",
        },
    )
    meta: dict = {"import_row_errors": len(err_list), "sha256": digest}
    if err_list:
        meta["import_errors"] = err_list
    return success({"created": created, "errors": err_list}, meta=meta)


@router.get("")
async def list_servicios(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    """List servicios owned by the current user."""
    items = await servicio_svc.list(db, filters={"user_id": current_user.id})
    return success([ServicioRead.model_validate(x).model_dump(mode="json") for x in items])


@router.get("/{id}")
async def get_servicio(
    entity: Servicio = Depends(require_ownership(servicio_svc)),
):
    """Get a single owned servicio by ID (404 if not owned)."""
    return success(ServicioRead.model_validate(entity).model_dump(mode="json"))


@router.post("", status_code=201)
async def create_servicio(
    entity_in: ServicioCreate,
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    """Create a new servicio for the current user."""
    entity = await servicio_svc.create(db, entity_in, extra={"user_id": current_user.id})
    return success(ServicioRead.model_validate(entity).model_dump(mode="json"))


@router.patch("/{id}")
async def update_servicio(
    entity_in: ServicioUpdate,
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
    entity: Servicio = Depends(require_ownership(servicio_svc)),
):
    """Partially update an owned servicio (404 if not owned)."""
    updated = await servicio_svc.update(db, entity.id, entity_in, scope={"user_id": current_user.id})
    return success(ServicioRead.model_validate(updated).model_dump(mode="json"))


@router.delete("/{id}")
async def delete_servicio(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
    entity: Servicio = Depends(require_ownership(servicio_svc)),
):
    """Delete an owned servicio (404 if not owned)."""
    await servicio_svc.delete(db, entity.id, scope={"user_id": current_user.id})
    return success(None, meta={"message": "Servicio deleted"})
